public sealed class StructureDefinitionV3
{
    private readonly ReadOnlyCollection<StructureFootprintOffsetV3> _offsets;
    private readonly ReadOnlyCollection<StructureOrientationV3> _orientations;
    private readonly ReadOnlyCollection<StructureMaterialRequirementV3> _materials;
    public StructureDefinitionV3(string id,string name,IEnumerable<StructureFootprintOffsetV3> offsets,IEnumerable<StructureOrientationV3> orientations,IEnumerable<StructureMaterialRequirementV3> materials,float seconds,bool blocks,StructurePlacementModeV3 mode,bool canBeDemolished=false,float baseDemolitionDurationSeconds=4f,RestFacilitySpecV3? restFacility=null,StructureMovementKindV3? movementKind=null,StructureRoomBoundaryKindV3 roomBoundaryKind=StructureRoomBoundaryKindV3.None,ConstructionCostModeV3 costMode=ConstructionCostModeV3.FixedRecipe,ConstructionMaterialTagV3 allowedMaterialTags=ConstructionMaterialTagV3.None,int baseMaterialAmount=0,ResourceTypeV3? defaultMaterialResourceType=null,float baseMaxHealth=200f,ConstructionDisplayCategoryV3 displayCategory=ConstructionDisplayCategoryV3.FurnitureAndLiving,int displayOrder=0)
    {
        if(string.IsNullOrWhiteSpace(id)||string.IsNullOrWhiteSpace(name))throw new ArgumentException("Definition id and name are required.");
        List<StructureFootprintOffsetV3> footprint=offsets?.ToList()??new();if(footprint.Count==0||footprint.Distinct().Count()!=footprint.Count)throw new ArgumentException("Footprint must contain unique cells.");
        List<StructureOrientationV3> allowed=orientations?.Distinct().OrderBy(x=>x).ToList()??new();if(allowed.Count==0)throw new ArgumentException("At least one orientation is required.");
        List<StructureMaterialRequirementV3> required=materials?.ToList()??new();if(required.Count==0||required.Any(x=>x.RequiredAmount<1)||required.Select(x=>x.ResourceType).Distinct().Count()!=required.Count)throw new ArgumentException("Material requirements are invalid.");
        if(seconds<=0||baseMaxHealth<=0)throw new ArgumentOutOfRangeException(nameof(seconds));if(canBeDemolished&&(!float.IsFinite(baseDemolitionDurationSeconds)||baseDemolitionDurationSeconds<=0))throw new ArgumentOutOfRangeException(nameof(baseDemolitionDurationSeconds));if(costMode==ConstructionCostModeV3.SelectableMaterial&&(baseMaterialAmount<1||defaultMaterialResourceType==null||allowedMaterialTags==ConstructionMaterialTagV3.None))throw new ArgumentException("Selectable material metadata is invalid.");DefinitionId=id;DisplayName=name;_offsets=footprint.AsReadOnly();_orientations=allowed.AsReadOnly();_materials=required.AsReadOnly();BaseConstructionDurationSeconds=seconds;MovementKind=movementKind??(blocks?StructureMovementKindV3.Blocking:StructureMovementKindV3.NonBlocking);BlocksMovement=MovementKind==StructureMovementKindV3.Blocking;PlacementMode=mode;CanBeDemolished=canBeDemolished;BaseDemolitionDurationSeconds=baseDemolitionDurationSeconds;RestFacility=restFacility;RoomBoundaryKind=roomBoundaryKind;CostMode=costMode;AllowedMaterialTags=allowedMaterialTags;BaseMaterialAmount=baseMaterialAmount;DefaultMaterialResourceType=defaultMaterialResourceType;BaseMaxHealth=baseMaxHealth;DisplayCategory=displayCategory;DisplayOrder=displayOrder;if(id==StructureDefinitionCatalogV3.WoodenWallId){CostMode=ConstructionCostModeV3.SelectableMaterial;AllowedMaterialTags=ConstructionMaterialTagV3.Structural;BaseMaterialAmount=5;DefaultMaterialResourceType=ResourceTypeV3.WoodPlank;BaseMaxHealth=200;DisplayCategory=ConstructionDisplayCategoryV3.Structure;DisplayOrder=10;}else if(id==StructureDefinitionCatalogV3.WoodenDoorId){CostMode=ConstructionCostModeV3.SelectableMaterial;AllowedMaterialTags=ConstructionMaterialTagV3.Door;BaseMaterialAmount=6;DefaultMaterialResourceType=ResourceTypeV3.WoodPlank;BaseMaxHealth=160;DisplayCategory=ConstructionDisplayCategoryV3.Structure;DisplayOrder=20;}
    }
    public string DefinitionId{get;}public string DisplayName{get;}public IReadOnlyList<StructureFootprintOffsetV3> BaseFootprintOffsets=>_offsets;public IReadOnlyList<StructureOrientationV3> AllowedOrientations=>_orientations;public IReadOnlyList<StructureMaterialRequirementV3> RequiredMaterials=>_materials;public float BaseConstructionDurationSeconds{get;}public bool BlocksMovement{get;}public StructureMovementKindV3 MovementKind{get;}public StructureRoomBoundaryKindV3 RoomBoundaryKind{get;}public StructurePlacementModeV3 PlacementMode{get;}public bool CanBeDemolished{get;}public float BaseDemolitionDurationSeconds{get;}public RestFacilitySpecV3? RestFacility{get;}public ConstructionCostModeV3 CostMode{get;}public ConstructionMaterialTagV3 AllowedMaterialTags{get;}public int BaseMaterialAmount{get;}public ResourceTypeV3? DefaultMaterialResourceType{get;}public float BaseMaxHealth{get;}public ConstructionDisplayCategoryV3 DisplayCategory{get;}public int DisplayOrder{get;}
    public IReadOnlyList<StructureMaterialRequirementV3> ResolveRequirements(ResourceTypeV3? material){if(CostMode==ConstructionCostModeV3.FixedRecipe)return RequiredMaterials;if(material==null||!ConstructionMaterialContentV3.TryGet(material.Value,out var d)||d==null||(d.Tags&AllowedMaterialTags)==0)throw new ArgumentException("Material is not allowed for this structure.");return new[]{new StructureMaterialRequirementV3(material.Value,BaseMaterialAmount)};}
}

