public static class StructureFootprintResolverV3
{
    public static ResolvedStructureFootprintV3 Resolve(StructureDefinitionV3 definition,GlobalCellCoord anchor,StructureOrientationV3 orientation)
    {if(!definition.AllowedOrientations.Contains(orientation))throw new ArgumentException("Orientation is not allowed.");List<Vector2I> rotated=definition.BaseFootprintOffsets.Select(x=>Rotate(x,orientation)).ToList();int minX=rotated.Min(x=>x.X),minY=rotated.Min(x=>x.Y);List<GlobalCellCoord> cells=rotated.Select(x=>new GlobalCellCoord(anchor.Value+new Vector2I(x.X-minX,x.Y-minY))).Distinct().OrderBy(x=>x.Value.Y).ThenBy(x=>x.Value.X).ToList();int maxX=cells.Max(x=>x.Value.X),maxY=cells.Max(x=>x.Value.Y);return new(cells,new(anchor.Value,new Vector2I(maxX-anchor.Value.X+1,maxY-anchor.Value.Y+1)));}
    public static GlobalCellCoord ResolveLocalCell(StructureDefinitionV3 definition,GlobalCellCoord anchor,StructureOrientationV3 orientation,StructureFootprintOffsetV3 localCell)
    {if(!definition.AllowedOrientations.Contains(orientation))throw new ArgumentException("Orientation is not allowed.");List<Vector2I> rotated=definition.BaseFootprintOffsets.Select(x=>Rotate(x,orientation)).ToList();Vector2I target=Rotate(localCell,orientation);int minX=rotated.Min(x=>x.X),minY=rotated.Min(x=>x.Y);return new(anchor.Value+new Vector2I(target.X-minX,target.Y-minY));}
    private static Vector2I Rotate(StructureFootprintOffsetV3 value,StructureOrientationV3 orientation)=>orientation switch{StructureOrientationV3.Deg0=>new(value.X,value.Y),StructureOrientationV3.Deg90=>new(-value.Y,value.X),StructureOrientationV3.Deg180=>new(-value.X,-value.Y),_=>new(value.Y,-value.X)};
}

