public sealed class ConstructionMaterialBufferV3
{
    private readonly Dictionary<ResourceTypeV3,int> _required=new(),_delivered=new();
    public ConstructionMaterialBufferV3(IEnumerable<StructureMaterialRequirementV3> requirements){foreach(var r in requirements){if(r.RequiredAmount<1||_required.ContainsKey(r.ResourceType))throw new ArgumentException("Invalid material requirement.");_required.Add(r.ResourceType,r.RequiredAmount);_delivered.Add(r.ResourceType,0);}if(_required.Count==0)throw new ArgumentException("Materials are required.");}
    public int GetRequiredAmount(ResourceTypeV3 type)=>_required.GetValueOrDefault(type);public int GetDeliveredAmount(ResourceTypeV3 type)=>_delivered.GetValueOrDefault(type);public int GetMissingAmount(ResourceTypeV3 type)=>Math.Max(0,GetRequiredAmount(type)-GetDeliveredAmount(type));public int GetTotalMissingAmount()=>_required.Keys.Sum(GetMissingAmount);public bool CanAccept(ResourceTypeV3 type,int amount)=>amount>0&&_required.ContainsKey(type)&&amount<=GetMissingAmount(type);
    public bool TryDeliver(ResourceTypeV3 type,int amount,out string reason){if(!CanAccept(type,amount)){reason="Material amount or type is not accepted.";return false;}_delivered[type]=checked(_delivered[type]+amount);reason=string.Empty;return true;}
    public bool TryWithdrawAll(out IReadOnlyList<StructureMaterialRequirementV3> snapshot){snapshot=GetDeliveredMaterialsSnapshot();foreach(ResourceTypeV3 type in _delivered.Keys.ToList())_delivered[type]=0;return true;}
    public IReadOnlyList<StructureMaterialRequirementV3> GetRequiredMaterialsSnapshot()=>_required.OrderBy(x=>x.Key).Select(x=>new StructureMaterialRequirementV3(x.Key,x.Value)).ToList().AsReadOnly();public IReadOnlyList<StructureMaterialRequirementV3> GetDeliveredMaterialsSnapshot()=>_delivered.Where(x=>x.Value>0).OrderBy(x=>x.Key).Select(x=>new StructureMaterialRequirementV3(x.Key,x.Value)).ToList().AsReadOnly();public bool IsComplete=>GetTotalMissingAmount()==0;
}

public enum ConstructionBlueprintStatusV3{AwaitingMaterials,ReadyToBuild,UnderConstruction,WaitingForFootprintClear,Completed,Cancelled,Failed}
public sealed class ConstructionBlueprintStateV3
{
    private readonly ReadOnlyCollection<GlobalCellCoord> _cells;
    public ConstructionBlueprintStateV3(string id,string company,string definition,GlobalCellCoord anchor,StructureOrientationV3 orientation,IEnumerable<GlobalCellCoord> cells,ConstructionMaterialBufferV3 buffer,DateTime created,ResourceTypeV3? materialResourceType=null,float requiredWorkSeconds=0,float expectedMaxHealth=0){if(!ConstructionBlueprintIdFactoryV3.IsValid(id)||string.IsNullOrWhiteSpace(company)||string.IsNullOrWhiteSpace(definition))throw new ArgumentException("Invalid blueprint identity.");List<GlobalCellCoord> list=cells.Distinct().OrderBy(x=>x.Value.Y).ThenBy(x=>x.Value.X).ToList();if(list.Count==0)throw new ArgumentException("Blueprint footprint is empty.");BlueprintId=id;CompanyId=company;DefinitionId=definition;AnchorCell=anchor;Orientation=orientation;_cells=list.AsReadOnly();MaterialBuffer=buffer;CreatedUtc=created.ToUniversalTime();MaterialResourceType=materialResourceType;RequiredWorkSeconds=requiredWorkSeconds;ExpectedMaxHealth=expectedMaxHealth;}
    public string BlueprintId{get;}public string CompanyId{get;}public string DefinitionId{get;}public GlobalCellCoord AnchorCell{get;}public StructureOrientationV3 Orientation{get;}public IReadOnlyList<GlobalCellCoord> OccupiedCells=>_cells;public ConstructionMaterialBufferV3 MaterialBuffer{get;}public ResourceTypeV3? MaterialResourceType{get;}public float RequiredWorkSeconds{get;}public float ExpectedMaxHealth{get;}public ConstructionBlueprintStatusV3 Status{get;private set;}=ConstructionBlueprintStatusV3.AwaitingMaterials;public float ConstructionProgressSeconds{get;private set;}public DateTime CreatedUtc{get;}public int Revision{get;private set;}
    public void RefreshMaterialStatus(){if(Status is ConstructionBlueprintStatusV3.Cancelled or ConstructionBlueprintStatusV3.Completed)return;Status=MaterialBuffer.IsComplete?ConstructionBlueprintStatusV3.ReadyToBuild:ConstructionBlueprintStatusV3.AwaitingMaterials;Revision++;}
    public bool TryBeginConstruction(out string reason){if(!MaterialBuffer.IsComplete){reason="MaterialsMissing";return false;}Status=ConstructionBlueprintStatusV3.UnderConstruction;Revision++;reason=string.Empty;return true;}
    public void AddProgress(float seconds){if(Status==ConstructionBlueprintStatusV3.UnderConstruction&&seconds>0){ConstructionProgressSeconds+=seconds;Revision++;}}
    internal void RestoreProgress(ConstructionBlueprintStatusV3 status,float progress,int revision){Status=status;ConstructionProgressSeconds=progress;Revision=revision;}
    public void SetWaitingForClear(){Status=ConstructionBlueprintStatusV3.WaitingForFootprintClear;Revision++;}public void MarkCompleted(){Status=ConstructionBlueprintStatusV3.Completed;Revision++;}public void MarkCancelled(){Status=ConstructionBlueprintStatusV3.Cancelled;Revision++;}
}

public sealed class StructureStateV3
{
    private readonly ReadOnlyCollection<GlobalCellCoord> _cells;private readonly ReadOnlyCollection<StructureMaterialRequirementV3> _materials;
    public StructureStateV3(string id,string company,string definition,GlobalCellCoord anchor,StructureOrientationV3 orientation,IEnumerable<GlobalCellCoord> cells,IEnumerable<StructureMaterialRequirementV3> materials,bool blocks,DateTime completed,StructureMovementKindV3? movementKind=null,StructureRoomBoundaryKindV3 roomBoundaryKind=StructureRoomBoundaryKindV3.None,ResourceTypeV3? materialResourceType=null,float maxHealth=0){if(!StructureIdFactoryV3.IsValid(id))throw new ArgumentException("Invalid structure id.");List<GlobalCellCoord> list=cells.Distinct().OrderBy(x=>x.Value.Y).ThenBy(x=>x.Value.X).ToList();if(list.Count==0)throw new ArgumentException("Empty structure footprint.");StructureId=id;CompanyId=company;DefinitionId=definition;AnchorCell=anchor;Orientation=orientation;_cells=list.AsReadOnly();_materials=materials.ToList().AsReadOnly();MovementKind=movementKind??(blocks?StructureMovementKindV3.Blocking:StructureMovementKindV3.NonBlocking);BlocksMovement=MovementKind==StructureMovementKindV3.Blocking;RoomBoundaryKind=roomBoundaryKind;CompletedUtc=completed.ToUniversalTime();MaterialResourceType=materialResourceType;MaxHealth=maxHealth>0?maxHealth:200;CurrentHealth=MaxHealth;}
    public string StructureId{get;}public string CompanyId{get;}public string DefinitionId{get;}public GlobalCellCoord AnchorCell{get;}public StructureOrientationV3 Orientation{get;}public IReadOnlyList<GlobalCellCoord> OccupiedCells=>_cells;public IReadOnlyList<StructureMaterialRequirementV3> EmbeddedMaterials=>_materials;public ResourceTypeV3? MaterialResourceType{get;}public float CurrentHealth{get;private set;}public float MaxHealth{get;}public bool BlocksMovement{get;}public StructureMovementKindV3 MovementKind{get;}public StructureRoomBoundaryKindV3 RoomBoundaryKind{get;}public DateTime CompletedUtc{get;}
